 822→    private static boolean getShowGutenbergInfoPopupForTheNewPosts(PrefKey key, String siteURL) {
 823→        if (TextUtils.isEmpty(siteURL)) {
 824→            return false;
 825→        }
 826→
 827→        Set<String> urls;
 828→        try {
 829→            urls = prefs().getStringSet(key.name(), null);
 830→        } catch (ClassCastException exp) {
 831→            // no operation - This should not happen.
 832→            return false;
 833→        }
 834→        // Check if the current site address is available in the set.
 835→        boolean flag = false;
 836→        if (urls != null) {
 837→            if (urls.contains(siteURL)) {
 838→                flag = true;
 839→                // remove the flag from Prefs
 840→                setShowGutenbergInfoPopupForTheNewPosts(key, siteURL, false);
 841→            }
 842→        }
 843→
 844→        return flag;
 845→    }
 846→
 847→    private static void setShowGutenbergInfoPopupForTheNewPosts(PrefKey key, String siteURL, boolean show) {
 848→        if (TextUtils.isEmpty(siteURL)) {
 849→            return;
 850→        }
 851→        Set<String> urls;
 852→        try {
 853→            urls = prefs().getStringSet(key.name(), null);
 854→        } catch (ClassCastException exp) {
 855→            // nope - this should never happens
 856→            return;
 857→        }
 858→
 859→        Set<String> newUrls = new HashSet<>();
 860→        // re-add the old urls here
 861→        if (urls != null) {
 862→            newUrls.addAll(urls);
 863→        }
 864→
 865→        // 1. First remove & 2. add if necessary
 866→        newUrls.remove(siteURL);
 867→        if (show) {
 868→            newUrls.add(siteURL);
 869→        }
 870→
 871→        SharedPreferences.Editor editor = prefs().edit();
 872→        editor.putStringSet(key.name(), newUrls);
 873→        editor.apply();
 874→    }
