1035→        // remove this ID if it already exists in the list
1036→        int index = currentIds.indexOf(localId);
1037→        if (index > -1) {
1038→            currentIds.remove(index);
1039→        }
1040→
1041→        // add this ID to the front of the list
1042→        currentIds.add(0, localId);
1043→
1044→        // remove at max
1045→        if (currentIds.size() > MAX_RECENTLY_PICKED_SITES_TO_SAVE) {
1046→            currentIds.remove(MAX_RECENTLY_PICKED_SITES_TO_SAVE);
1047→        }
1048→
1049→        // store in prefs
1050→        String idsAsString = TextUtils.join(",", currentIds);
1051→        setString(DeletablePrefKey.RECENTLY_PICKED_SITE_IDS, idsAsString);
1052→    }
