108→    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
109→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
110→            return true
111→        }
112→        if (oldItem is LoadingItem && newItem is LoadingItem) {
113→            return oldItem.localOrRemoteId == newItem.localOrRemoteId
114→        }
115→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
116→            return oldItem.data.localPostId == newItem.data.localPostId
117→        }
118→        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
119→            return when (oldItem.localOrRemoteId) {
120→                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
121→                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
122→            }
123→        }
124→        return false
125→    }
