106→    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
107→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
108→            return true
109→        }
110→        if (oldItem is LoadingItem && newItem is LoadingItem) {
111→            return oldItem.localOrRemoteId == newItem.localOrRemoteId
