126→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
127→            return true
128→        }
129→        if (oldItem is LoadingItem && newItem is LoadingItem) {
130→            return when (oldItem.localOrRemoteId) {
131→                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
132→                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
133→            }
134→        }
135→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
136→            return oldItem.data == newItem.data
137→        }
138→        return false
139→    }
