141→    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
142→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
143→            /**
144→             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
145→             *
146→             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
147→             * suppresses the default ItemAnimator, which is all we need in this case.
