 445→    public static ReaderTag getReaderTag() {
 446→        String tagName = getString(DeletablePrefKey.READER_TAG_NAME);
 447→        if (TextUtils.isEmpty(tagName)) {
 448→            return null;
 449→        }
 450→        int tagType = getInt(DeletablePrefKey.READER_TAG_TYPE);
 451→
 452→        boolean wasFollowing = false;
 453→
 454→        // The intention here is to check if the `DeletablePrefKey.READER_TAG_WAS_FOLLOWING` key
 455→        // was present at all in the Shared Prefs.
 456→        // We could have it not set for example in cases where user is upgrading from
 457→        // a previous version of the app. In those cases we do not have enough information as of the saved
 458→        // tag was a Following tag or not, so (as with empty `DeletablePrefKey.READER_TAG_NAME`)
 459→        // let's do not use this piece of information.
 460→        String wasFallowingString = getString(DeletablePrefKey.READER_TAG_WAS_FOLLOWING);
 461→        if (TextUtils.isEmpty(wasFallowingString)) return null;
 462→
 463→        wasFollowing = getBoolean(DeletablePrefKey.READER_TAG_WAS_FOLLOWING, false);
 464→
 465→        return ReaderUtils.getTagFromTagName(tagName, ReaderTagType.fromInt(tagType), wasFollowing);
 466→    }
