 468→    public static void setReaderTag(ReaderTag tag) {
 469→        if (tag != null && !TextUtils.isEmpty(tag.getTagSlug())) {
 470→            setString(DeletablePrefKey.READER_TAG_NAME, tag.getTagSlug());
 471→            setInt(DeletablePrefKey.READER_TAG_TYPE, tag.tagType.toInt());
 472→            setBoolean(
 473→                    DeletablePrefKey.READER_TAG_WAS_FOLLOWING,
 474→                    tag.isFollowedSites() || tag.isDefaultInMemoryTag()
 475→            );
 476→        } else {
 477→            prefs().edit()
 478→                   .remove(DeletablePrefKey.READER_TAG_NAME.name())
 479→                   .remove(DeletablePrefKey.READER_TAG_TYPE.name())
 480→                   .remove(DeletablePrefKey.READER_TAG_WAS_FOLLOWING.name())
 481→                   .apply();
 482→        }
 483→    }
