107→private val PostListDiffItemCallback = object : DiffUtil.ItemCallback<PostListItemType>() {
108→    override fun areItemsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
109→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
110→            return true
111→        }
112→        if (oldItem is LoadingItem && newItem is LoadingItem) {
113→            return oldItem.localOrRemoteId == newItem.localOrRemoteId
114→        }
115→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
116→            return oldItem.data.localPostId == newItem.data.localPostId
117→        }
118→        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
119→            return when (oldItem.localOrRemoteId) {
120→                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
121→                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
122→            }
123→        }
124→        return false
125→    }
126→
127→    override fun areContentsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
128→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
129→            return true
130→        }
131→        if (oldItem is LoadingItem && newItem is LoadingItem) {
132→            return when (oldItem.localOrRemoteId) {
133→                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
134→                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
135→            }
136→        }
137→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
138→            return oldItem.data == newItem.data
139→        }
140→        return false
141→    }
142→
143→    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
144→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
145→            /**
146→             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
147→             *
148→             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
149→             * suppresses the default ItemAnimator, which is all we need in this case.
150→             */
151→            if (oldItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
152→                newItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
153→                oldItem.data.progressBarUiState.progress != newItem.data.progressBarUiState.progress
154→            ) {
155→                return true
156→            }
157→        }
158→        return super.getChangePayload(oldItem, newItem)
159→    }
