111→            return oldItem.localOrRemoteId == newItem.localOrRemoteId
112→        }
113→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
114→            return oldItem.data.localPostId == newItem.data.localPostId
115→        }
116→        if (oldItem is LoadingItem && newItem is PostListItemUiState) {
117→            return when (oldItem.localOrRemoteId) {
118→                is LocalId -> oldItem.localOrRemoteId == newItem.data.localPostId.id
119→                is RemoteId -> oldItem.localOrRemoteId == newItem.data.remotePostId.id
120→            }
121→        }
122→        return false
123→    }
124→
125→    override fun areContentsTheSame(oldItem: PostListItemType, newItem: PostListItemType): Boolean {
126→        if (oldItem is EndListIndicatorItem && newItem is EndListIndicatorItem) {
127→            return true
128→        }
129→        if (oldItem is LoadingItem && newItem is LoadingItem) {
130→            return when (oldItem.localOrRemoteId) {
131→                is LocalId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? LocalId)?.value
132→                is RemoteId -> oldItem.localOrRemoteId.value == (newItem.localOrRemoteId as? RemoteId)?.value
133→            }
134→        }
135→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
136→            return oldItem.data == newItem.data
137→        }
138→        return false
139→    }
140→
141→    override fun getChangePayload(oldItem: PostListItemType, newItem: PostListItemType): Any? {
142→        if (oldItem is PostListItemUiState && newItem is PostListItemUiState) {
143→            /**
144→             * Suppresses the default animation if the progress has changed to prevent blinking as the upload progresses
145→             *
146→             * We don't need to use the payload in onBindViewHolder unless we want to. Passing a non-null value
147→             * suppresses the default ItemAnimator, which is all we need in this case.
148→             */
149→            if (oldItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
150→                newItem.data.progressBarUiState is ProgressBarUiState.Determinate &&
151→                oldItem.data.progressBarUiState.progress != newItem.data.progressBarUiState.progress
152→            ) {
153→                return true
154→            }
155→        }
156→        return super.getChangePayload(oldItem, newItem)
157→    }
158→}
